/**
 * MedX dialog runtime — runs on `npm run start` via medx-runtime-registry.cjs
 * Alert-dialog manager for confirmations, destructive actions, and multi-step forms.
 */
const DIALOG_SIZES = Object.freeze({
  sm: { maxWidth: "24rem", padding: "p-4" },
  md: { maxWidth: "32rem", padding: "p-6" },
  lg: { maxWidth: "48rem", padding: "p-6" },
  xl: { maxWidth: "64rem", padding: "p-8" },
});

const DIALOG_PRESETS = Object.freeze({
  confirmDeleteLot: {
    title: "Delete lot record?",
    description:
      "This will permanently remove lot LOT-A8F2K91M and all associated movement history. This action cannot be undone.",
    size: "sm",
    confirmLabel: "Delete lot",
    cancelLabel: "Keep lot",
    destructive: true,
    requireConfirmText: "DELETE",
  },
  quarantineLot: {
    title: "Quarantine lot",
    description:
      "Quarantined lots are blocked from dispatch and flagged for compliance review. Continue?",
    size: "md",
    confirmLabel: "Quarantine",
    cancelLabel: "Cancel",
    destructive: false,
    variant: "warning",
  },
  approvePurchaseOrder: {
    title: "Approve purchase order",
    description: "Approving PO-2026-0842 will notify the supplier and lock line-item pricing.",
    size: "md",
    confirmLabel: "Approve",
    cancelLabel: "Review later",
    destructive: false,
  },
  receiveBatch: {
    title: "Confirm batch receive",
    description: "Receive BATCH-000042 into East Distribution Center? Quantities will be updated immediately.",
    size: "lg",
    confirmLabel: "Confirm receive",
    cancelLabel: "Cancel",
    destructive: false,
    fields: ["batchId", "warehouseId", "lineItemCount"],
  },
  disconnectWallet: {
    title: "Disconnect wallet?",
    description: "On-chain traceability signing will be disabled until you reconnect a supplier wallet.",
    size: "sm",
    confirmLabel: "Disconnect",
    cancelLabel: "Stay connected",
    destructive: true,
  },
  complianceOverride: {
    title: "Compliance override required",
    description:
      "Dispatching expired or recalled lots requires manager authorization and an audit log entry.",
    size: "md",
    confirmLabel: "Request override",
    cancelLabel: "Cancel dispatch",
    destructive: true,
    requireConfirmText: "OVERRIDE",
  },
});

const DIALOG_VARIANTS = Object.freeze({
  default: { overlay: "bg-black/50", accent: "text-foreground" },
  warning: { overlay: "bg-amber-500/10", accent: "text-amber-700" },
  destructive: { overlay: "bg-destructive/10", accent: "text-destructive" },
});

const dialogStack = [];
const dialogListeners = new Set();
const dialogHistory = [];
let dialogIdSeq = 0;

function generateDialogId() {
  dialogIdSeq += 1;
  return `medx-dialog-${dialogIdSeq}`;
}

function resolveDialogPreset(presetKey) {
  return DIALOG_PRESETS[presetKey] ?? null;
}

function openDialog(config) {
  const preset = config.preset ? resolveDialogPreset(config.preset) : null;
  const variant = config.variant ?? preset?.variant ?? (preset?.destructive ? "destructive" : "default");
  const size = config.size ?? preset?.size ?? "md";

  const dialog = {
    id: config.id ?? generateDialogId(),
    preset: config.preset ?? null,
    title: config.title ?? preset?.title ?? "Dialog",
    description: config.description ?? preset?.description ?? "",
    size,
    sizeStyles: DIALOG_SIZES[size] ?? DIALOG_SIZES.md,
    variant,
    variantStyles: DIALOG_VARIANTS[variant] ?? DIALOG_VARIANTS.default,
    confirmLabel: config.confirmLabel ?? preset?.confirmLabel ?? "Confirm",
    cancelLabel: config.cancelLabel ?? preset?.cancelLabel ?? "Cancel",
    destructive: config.destructive ?? preset?.destructive ?? false,
    requireConfirmText: config.requireConfirmText ?? preset?.requireConfirmText ?? null,
    confirmTextInput: "",
    fields: config.fields ?? preset?.fields ?? [],
    data: config.data ?? {},
    open: true,
    loading: false,
    steps: config.steps ?? null,
    currentStep: 0,
    focusTrap: { initialFocus: "confirm", restoreFocus: true },
  aria: {
      labelledBy: `dialog-title-${dialogIdSeq}`,
      describedBy: `dialog-desc-${dialogIdSeq}`,
      role: "alertdialog",
    },
    onConfirm: typeof config.onConfirm === "function" ? config.onConfirm : null,
    onCancel: typeof config.onCancel === "function" ? config.onCancel : null,
    openedAt: Date.now(),
  };

  dialogStack.push(dialog);
  notifyDialogListeners("open", dialog);
  return dialog;
}

function closeDialog(id, reason = "user", result = null) {
  const index = dialogStack.findIndex((d) => d.id === id);
  if (index === -1) return false;

  const [dialog] = dialogStack.splice(index, 1);
  dialog.open = false;
  dialog.closedAt = Date.now();
  dialog.closeReason = reason;
  dialog.result = result;

  dialogHistory.push({
    id: dialog.id,
    preset: dialog.preset,
    title: dialog.title,
    reason,
    result,
    durationMs: dialog.closedAt - dialog.openedAt,
  });

  notifyDialogListeners("close", dialog);
  return true;
}

function validateDialogConfirm(dialog) {
  if (!dialog.requireConfirmText) return { valid: true };
  const expected = dialog.requireConfirmText;
  const actual = String(dialog.confirmTextInput ?? "").trim();
  if (actual !== expected) {
    return { valid: false, reason: `Type "${expected}" to confirm` };
  }
  return { valid: true };
}

async function confirmDialog(id, confirmTextInput) {
  const dialog = dialogStack.find((d) => d.id === id);
  if (!dialog) return null;

  if (confirmTextInput !== undefined) dialog.confirmTextInput = confirmTextInput;
  const validation = validateDialogConfirm(dialog);
  if (!validation.valid) return { success: false, ...validation };

  if (dialog.steps && dialog.currentStep < dialog.steps.length - 1) {
    dialog.currentStep += 1;
    notifyDialogListeners("step", dialog);
    return { success: true, advanced: true, step: dialog.currentStep };
  }

  dialog.loading = true;
  const result = { dialogId: id, data: dialog.data, confirmedAt: Date.now() };
  if (dialog.onConfirm) {
    try {
      await dialog.onConfirm(result);
    } catch (err) {
      dialog.loading = false;
      return { success: false, reason: err.message };
    }
  }
  closeDialog(id, "confirm", result);
  return { success: true, result };
}

function cancelDialog(id) {
  const dialog = dialogStack.find((d) => d.id === id);
  if (!dialog) return false;
  if (dialog.onCancel) dialog.onCancel({ dialogId: id, reason: "cancel" });
  return closeDialog(id, "cancel");
}

function getTopDialog() {
  return dialogStack[dialogStack.length - 1] ?? null;
}

function getDialogAriaSnapshot(id) {
  const dialog = dialogStack.find((d) => d.id === id) ?? dialogHistory.find((h) => h.id === id);
  if (!dialog) return null;
  return {
    role: "alertdialog",
    modal: true,
    labelledBy: `dialog-title-${id}`,
    describedBy: `dialog-desc-${id}`,
    destructive: dialog.destructive ?? false,
  };
}

function onDialogEvent(listener) {
  dialogListeners.add(listener);
  return () => dialogListeners.delete(listener);
}

function notifyDialogListeners(type, dialog) {
  for (const listener of dialogListeners) {
    try {
      listener({ type, dialog, stackDepth: dialogStack.length });
    } catch (err) {
      console.warn("[medx:ui:dialog] listener error", err.message);
    }
  }
}

function getDialogMetrics() {
  return {
    open: dialogStack.length,
    history: dialogHistory.length,
    destructiveOpen: dialogStack.filter((d) => d.destructive).length,
    requiringConfirmText: dialogStack.filter((d) => d.requireConfirmText).length,
  };
}

async function runMedxDialog() {
  console.log("[medx:ui:dialog] runtime initialized");
  console.log(
    `[medx:ui:dialog] sizes=${Object.keys(DIALOG_SIZES).length} presets=${Object.keys(DIALOG_PRESETS).length} variants=${Object.keys(DIALOG_VARIANTS).length}`,
  );

  const events = [];
  const confirmations = [];
  onDialogEvent((e) => events.push(e.type));

  openDialog({
    preset: "receiveBatch",
    data: { batchId: "BATCH-000042", warehouseId: "wh-east", lineItemCount: 12 },
    onConfirm: (r) => confirmations.push(r.data.batchId),
  });

  openDialog({
    preset: "confirmDeleteLot",
    data: { lotId: "LOT-A8F2K91M" },
    onConfirm: () => confirmations.push("deleted"),
  });

  const deleteDialog = getTopDialog();
  const failConfirm = await confirmDialog(deleteDialog.id, "WRONG");
  const passConfirm = await confirmDialog(deleteDialog.id, "DELETE");

  openDialog({ preset: "quarantineLot", data: { lotId: "LOT-B3D7H22P" } });
  cancelDialog(getTopDialog()?.id);

  openDialog({
    preset: "complianceOverride",
    data: { lotId: "LOT-E7H4M88V", reason: "emergency dispatch" },
    steps: ["review", "authorize", "confirm"],
  });
  const overrideDialog = getTopDialog();
  await confirmDialog(overrideDialog.id, "OVERRIDE");

  const metrics = getDialogMetrics();
  const aria = getDialogAriaSnapshot(overrideDialog?.id);

  console.log(`[medx:ui:dialog] open=${metrics.open} history=${metrics.history}`);
  console.log("[medx:ui:dialog] confirmFail", failConfirm?.reason);
  console.log("[medx:ui:dialog] confirmations", confirmations.join(","));
  console.log(`[medx:ui:dialog] events=${events.join(",")}`);
  console.log("[medx:ui:dialog] aria role=", aria?.role);
  console.log("[medx:ui:dialog] bootstrap complete");
}

module.exports = runMedxDialog;
